import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface SleepStage {
  name: string;
  value: number;
}

interface SleepData {
  lastNight: {
    duration: string;
    sleepQuality: string;
  };
  stages: SleepStage[];
  weeklyAverage: {
    duration: string;
    quality: string;
  };
}

export default function Widget() {
  const sleepData = response.data as SleepData;
  const { lastNight, stages, weeklyAverage } = sleepData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#303030', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600}>
              Sleep Quality
            </Typography>
            <Typography variant="body2" sx={{ color: '#BDBDBD', mb: 1 }}>
              Last Night: {lastNight.duration} - {lastNight.sleepQuality}
            </Typography>
            <Typography variant="body2" sx={{ color: '#BDBDBD' }}>
              Weekly Avg: {weeklyAverage.duration} - {weeklyAverage.quality}
            </Typography>
          </Box>

          <PieChart
            height={180}
            series={[
              {
                data: stages.map(stage => ({ id: stage.name, value: stage.value })),
                innerRadius: 0.6,
                outerRadius: 1,
                labelPosition: 'outside',
                labels: stages.map(stage => stage.name),
                colors: ['#FF7043', '#512DA8', '#1976D2'],
              },
            ]}
          />

          <Stack direction="row" spacing={1.5}>
            {stages.map(stage => (
              <Box key={stage.name}>
                <Typography variant="caption" color="text.secondary">
                  {stage.name}
                </Typography>
                <Typography variant="body2" fontWeight={500}>
                  {stage.value}%
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
